// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.impl;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.catchThrowable;

import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.ValueExprEvaluationException;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

class ValueExprEvaluationExceptionReuseTest {

	@Test
	void valueExpressionFailuresDoNotShareThrowableState() {
		DefaultEvaluationStrategy strategy = new DefaultEvaluationStrategy(new EmptyTripleSource(), null);

		Throwable first = catchThrowable(
				() -> strategy.evaluate(new Var("missing"), EmptyBindingSet.getInstance()));
		assertThat(first).isInstanceOf(ValueExprEvaluationException.class);
		first.addSuppressed(new IllegalStateException("mutated"));

		Throwable second = catchThrowable(
				() -> strategy.evaluate(new Var("missing"), EmptyBindingSet.getInstance()));

		assertThat(second).isInstanceOf(ValueExprEvaluationException.class);
		assertThat(second).isNotSameAs(first);
		assertThat(second.getSuppressed()).isEmpty();
	}
}
